const newItems = [];

// Reach all the way back to grab the items directly from the Webhook node
const webhookItems = $('Receive Query Request').all();

for (const item of webhookItems) {
  // If there is no binary data attached, skip it
  if (!item.binary) continue;

  // Find all the files (e.g., 'file', 'data0', etc.)
  const binaryKeys = Object.keys(item.binary);

  // Split them up into individual items and rename them all to 'data'
  for (const key of binaryKeys) {
    newItems.push({
      json: item.json,
      binary: {
        data: item.binary[key]
      }
    });
  }
}

return newItems;

// Grab the text string that the LLM generated
const rawText = $input.first().json.output;

// Parse the text into an actual JSON array
const parsedData = JSON.parse(rawText);

// Return it so n8n treats each stakeholder as a separate item
return parsedData;

